+fn index_label_to_scalar(label: &IndexLabel) -> Scalar {
+    match label {
+        IndexLabel::Int64(v) => Scalar::Int64(*v),
+        IndexLabel::Utf8(v) => Scalar::Utf8(v.clone()),
+    }
+}
